import{_ as h,C as r,o as d,c as m,j as e,a as n,E as t,a3 as p}from"./chunks/framework.CVjg771q.js";const k=JSON.parse('{"title":"庄子·应帝王","description":"以无心之治、壶子示相与浑沌之死，收束内篇关于应物与治道的思考。","frontmatter":{"title":"庄子·应帝王","description":"以无心之治、壶子示相与浑沌之死，收束内篇关于应物与治道的思考。","category":"guide","aliases":["应帝王","庄子应帝王","zhuangzi chapter 07"],"source":["《庄子》","维基文库：庄子·应帝王"]},"headers":[],"relativePath":"daoism/zhuang-zi/chapter-07.md","filePath":"daoism/zhuang-zi/chapter-07.md","lastUpdated":1782666543000}'),c={name:"daoism/zhuang-zi/chapter-07.md"};function u(g,a,b,x,f,_){const i=r("DaoReadingPrelude"),o=r("DaoOriginalReadingGroup"),l=r("DaoLineGuide"),s=r("DaoKeywordCards");return d(),m("div",null,[a[0]||(a[0]=e("h1",{id:"庄子·应帝王",tabindex:"-1"},[n("庄子·应帝王 "),e("a",{class:"header-anchor",href:"#庄子·应帝王","aria-label":'Permalink to "庄子·应帝王"'},"​")],-1)),t(i,{title:"从无心之治与浑沌之死，看庄子如何应帝王",summary:"应帝王是《庄子》内篇最后一篇。它表面谈帝王之道，实则谈如何应物而不被物役。无名人、老聃、壶子、列子、浑沌等故事层层推进，最后以「日凿一窍，七日而浑沌死」收束，提醒人不要用人为机巧凿破自然完整。",points:[{label:"先看",text:"顺着无名人、老聃、壶子示相、列子归朴、浑沌之死几段走。"},{label:"再问",text:"「至人之用心若镜」为什么能成为应物之道？"},{label:"最后",text:"想一想：你是否也常用好意去替别人「凿窍」，反而破坏了本来的完整？"}],hint:"这一篇是内篇收束，重点不在权术，而在无心、虚静、应而不藏。"}),a[1]||(a[1]=e("h2",{id:"【原典层】原文",tabindex:"-1"},[n("【原典层】原文 "),e("a",{class:"header-anchor",href:"#【原典层】原文","aria-label":'Permalink to "【原典层】原文"'},"​")],-1)),t(o,{paragraphs:["齧缺問於王倪，四問而四不知。齧缺因躍而大喜，行以告蒲衣子。蒲衣子曰：「而乃今知之乎？有虞氏不及泰氏。有虞氏，其猶藏仁以要人，亦得人矣，而未始出於非人。泰氏，其臥徐徐，其覺于于，一以己為馬，一以己為牛，其知情信，其德甚真，而未始入於非人。肩吾見狂接輿。狂接輿曰：「日中始何以語女？肩吾曰：「告我：君人者，以己出經式義度，人孰敢不聽而化諸！狂接輿曰：「是欺德也。","其於治天下也，猶涉海鑿河，而使蚉負山也。夫聖人之治也，治外乎？正而後行，確乎能其事者而已矣。且鳥高飛以避矰弋之害，鼷鼠深穴乎神丘之下，以避熏鑿之患，而曾二蟲之無知！天根遊於殷陽，至蓼水之上，適遭無名人而問焉，曰：「請問為天下。無名人曰：「去！汝鄙人也，何問之不豫也！予方將與造物者為人，厭則又乘夫莽眇之鳥，以出六極之外，而遊無何有之鄉，以處壙埌之野。","汝又何帠以治天下感予之心為？又復問。無名人曰：「汝遊心於淡，合氣於漠，順物自然，而無容私焉，而天下治矣。陽子居見老聃曰：「有人於此，嚮疾強梁，物徹疏明，學道不倦。如是者，可比明王乎？老聃曰：「是於聖人也，胥易技係，勞形怵心者也。且也虎豹之文來田，猿狙之便、執嫠之狗來藉。如是者，可比明王乎？陽子居蹴然曰：「敢問明王之治。","老聃曰：「明王之治，功蓋天下而似不自己，化貸萬物而民弗恃，有莫舉名，使物自喜，立乎不測，而遊於無有者也。鄭有神巫曰季咸，知人之生死存亡，禍福壽夭，期以歲月旬日，若神。鄭人見之，皆棄而走。列子見之而心醉，歸以告壺子，曰：「始吾以夫子之道為至矣，則又有至焉者矣。壺子曰：「吾與汝既其文，未既其實，而固得道與？眾雌而無雄，而又奚卵焉！","而以道與世亢必信，夫故使人得而相女。嘗試與來，以予示之。明日，列子與之見壺子。出而謂列子曰：「嘻！子之先生死矣，弗活矣，不以旬數矣！吾見怪焉，見溼灰焉。列子入，泣涕沾襟，以告壺子。壺子曰：「鄉吾示之以地文，萌乎不震不正。是殆見吾杜德機也。嘗又與來。明日，又與之見壺子。出而謂列子曰：「幸矣！子之先生遇我也。有瘳矣，全然有生矣。吾見其杜權矣。列子入，以告壺子。","壺子曰：「鄉吾示之以天壤，名實不入，而機發於踵。是殆見吾善者機也。嘗又與來。明日，又與之見壺子。出而謂列子曰：「子之先生不齊，吾無得而相焉。試齊，且復相之。列子入，以告壺子。壺子曰：「吾鄉示之以太沖莫勝。是殆見吾衡氣機也。鯢桓之審為淵，止水之審為淵，流水之審為淵。淵有九名，此處三焉。嘗又與來。明日，又與之見壺子。立未定，自失而走。壺子曰：「追之！","列子追之不及，反以報壺子，曰：「已滅矣，已失矣，吾弗及也。壺子曰：「鄉吾示之以未始出吾宗。吾與之虛而委蛇，不知其誰何，因以為弟靡，因以為波流，故逃也。然後列子自以為未始學而歸，三年不出。為其妻爨，食豕如食人。於事無與親，彫琢復朴，塊然獨以其形立。紛而封哉，一以是終。無為名尸，無為謀府，無為事任，無為知主。體盡無窮，而遊無朕，盡其所受於天，而無見得，亦虛而已。","至人之用心若鏡，不將不迎，應而不藏，故能勝物而不傷。南海之帝為儵，北海之帝為忽，中央之帝為渾沌。儵與忽時相與遇於渾沌之地，渾沌待之甚善。儵與忽謀報渾沌之德，曰：「人皆有七竅，以視聽食息，此獨無有，嘗試鑿之。日鑿一竅，七日而渾沌死。"]}),t(l,{lines:[{label:"四不知",text:"齧缺问王倪，四问而四不知，开篇即破除以知识掌控万物的冲动。"},{label:"无名人",text:"无名人说顺物自然、无容私焉，而天下治矣。"},{label:"明王",text:"老聃谈明王之治：功盖天下而似不自己，化贷万物而民弗恃。"},{label:"壶子",text:"壶子四示其相，使季咸无从测度，说明真正的道不可被表相把握。"},{label:"若镜",text:"至人之用心若镜，不将不迎，应而不藏。"},{label:"浑沌",text:"儵忽为浑沌凿七窍，七日而浑沌死——人为善意也可能破坏自然。"}]}),a[2]||(a[2]=e("h2",{id:"【原典层】字词释义",tabindex:"-1"},[n("【原典层】字词释义 "),e("a",{class:"header-anchor",href:"#【原典层】字词释义","aria-label":'Permalink to "【原典层】字词释义"'},"​")],-1)),t(s,{items:[{term:"应帝王",pinyin:["yìng","dì","wáng"],meaning:"不是教帝王权术，而是讲面对天下万物时如何无心而应。"},{term:"无名人",pinyin:["wú","míng","rén"],meaning:"寓言人物，象征不以名位立身、不以私意治世。"},{term:"顺物自然",pinyin:["shùn","wù","zì","rán"],meaning:"顺着万物自身的状态，不以私意强加干预。"},{term:"壶子",pinyin:["hú","zǐ"],meaning:"列子的老师，通过示相让神巫季咸无法测度其真实境界。"},{term:"至人用心若镜",pinyin:["zhì","rén","yòng","xīn","ruò","jìng"],meaning:"镜子不迎不送，只如实照见。至人应物而不藏，不被物伤。"},{term:"浑沌",pinyin:["hún","dùn"],meaning:"中央之帝，无七窍。象征未被人为分别凿开的自然完整。"},{term:"七窍",pinyin:["qī","qiào"],meaning:"眼耳口鼻等窍。儵忽为浑沌凿七窍，象征用人为标准改造自然。"}]}),a[3]||(a[3]=p("",15))])}const z=h(c,[["render",u]]);export{k as __pageData,z as default};
